import{c as a,Q as t,j as o,m as r}from"./chunks/framework.CdiUUa3G.js";const h=JSON.parse('{"title":"ADR-034 — Math rendering: KaTeX server-rendered at build","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-034.md","filePath":"adr/ADR-034.md"}'),i={name:"adr/ADR-034.md"};function n(s,e,d,l,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-034-—-math-rendering-katex-server-rendered-at-build" tabindex="-1">ADR-034 — Math rendering: KaTeX server-rendered at build <a class="header-anchor" href="#adr-034-—-math-rendering-katex-server-rendered-at-build" aria-label="Permalink to &quot;ADR-034 — Math rendering: KaTeX server-rendered at build&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-011 (with ADR-035, ADR-036) TA anchor · §components / primary-route-pages Related · PRD-008, ADR-014 (CI + GitHub Pages), ADR-016 (build-time assets), ADR-017 (i18n)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-008 / GitHub #39 introduce <code>/science</code>: an in-app encyclopedia covering ~40 physics concepts with formulas, diagrams, and prose. RFC-011 OQ-1 asked how to render math in section bodies. Four candidates: KaTeX server-rendered, KaTeX client-side, MathJax v3, hand-rolled SVG per formula. The trade-off pivots on bundle weight vs. authoring ergonomics.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="render-path-rfc-oq-1-—-option-a" tabindex="-1">Render path (RFC OQ-1 — Option A) <a class="header-anchor" href="#render-path-rfc-oq-1-—-option-a" aria-label="Permalink to &quot;Render path (RFC OQ-1 — Option A)&quot;">​</a></h3><p>Use <strong><a href="https://katex.org" target="_blank" rel="noreferrer">KaTeX</a></strong> to compile every <code>formula_latex</code> field into HTML at SvelteKit prerender time. The client receives static HTML + KaTeX&#39;s CSS only; the JavaScript library never ships to the browser.</p><p><strong>Implementation</strong>:</p><ul><li>Add <code>katex@^0.16</code> as a runtime dependency and <code>@types/katex</code> as devDependency.</li><li><code>src/lib/katex.ts</code> exposes <code>renderKatex(latex: string): string</code> — server-only helper called from <code>+page.server.ts</code> <code>load</code> functions during prerender.</li><li>KaTeX&#39;s CSS imported once at the science layout level (<code>src/routes/science/+layout.svelte</code>) so the fonts + glyphs are available offline.</li><li>LaTeX source authored in section JSON: <code>{ &quot;formula_latex&quot;: &quot;v = \\\\sqrt{\\\\mu \\\\cdot (2/r - 1/a)}&quot; }</code>.</li><li>The SvelteKit <code>prerender = true</code> directive on <code>/science/[tab]/[section]</code> ensures every section is a static HTML file — KaTeX never runs in the browser.</li></ul><h3 id="edge-cases-rfc-oq-1-—-option-d-fallback" tabindex="-1">Edge cases (RFC OQ-1 — Option D fallback) <a class="header-anchor" href="#edge-cases-rfc-oq-1-—-option-d-fallback" aria-label="Permalink to &quot;Edge cases (RFC OQ-1 — Option D fallback)&quot;">​</a></h3><p>For any formula that KaTeX cannot render (e.g. macros KaTeX rejects, custom layout), inline an SVG into the section&#39;s <code>formula_svg</code> field instead. Schema treats <code>formula_latex</code> and <code>formula_svg</code> as mutually exclusive optional fields.</p><h3 id="budget" tabindex="-1">Budget <a class="header-anchor" href="#budget" aria-label="Permalink to &quot;Budget&quot;">​</a></h3><ul><li>KaTeX CSS: ~30 KB minified gzipped, loaded once for the entire <code>/science</code> tree.</li><li>KaTeX JS: <strong>0 KB at runtime</strong> (server-rendered).</li><li>Authored formulas: LaTeX strings in JSON; ~10–20 across all 40 sections.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Authoring ergonomics of LaTeX without runtime cost. The encyclopedia can include rigorous formulas (vis-viva, Tsiolkovsky, orbital period) without inflating the JS bundle. Offline-capable per ADR-029 (PWA).</p><p><strong>Negative:</strong> Build time grows by the cost of running KaTeX over every <code>formula_latex</code> field — negligible at 40 sections, observable at 400+. Edge-case formulas need a separate SVG fallback path, which costs authoring time. KaTeX&#39;s CSS adds 30 KB to first paint of <code>/science</code>; trivially cached after.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Renderer entry point: <code>src/lib/katex.ts</code>.</li><li>Component wrapper: <code>src/lib/components/ScienceFormula.svelte</code> accepts pre-rendered HTML + caption.</li><li>Validation: <code>scripts/validate-data.ts</code> ensures every section with a <code>formula_latex</code> field produces valid HTML at build time (compile + assert non-empty output).</li><li>Deferred: client-side render path (RFC-011 OQ-1 Option B) — kept available as a fallback if SvelteKit&#39;s prerender ever can&#39;t statically resolve a section, but never invoked in steady state.</li></ul>',18)])])}const m=a(i,[["render",n]]);export{h as __pageData,m as default};
